import React, { useState, useMemo, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { 
  ShoppingBag, 
  LogOut, 
  Package, 
  BarChart2, 
  History, 
  ShieldCheck, 
  Search, 
  ShoppingCart, 
  User, 
  Phone, 
  ChevronDown,
  Trash2,
  Plus,
  Minus,
  X,
  UserCheck,
  UserPlus,
  AlertCircle,
  CheckCircle
} from 'lucide-react';

const Sales = () => {
  const navigate = useNavigate();

  // Mahsulotlar
  const [products] = useState([
    { id: 1, name: 'Mevalar toplami', price: 45000, stock: 50, image: 'https://images.unsplash.com/photo-1610832958506-aa56368176cf?auto=format&fit=crop&q=80&w=400' },
    { id: 2, name: 'Sabzavotlar seti', price: 32000, stock: 120, image: 'https://images.unsplash.com/photo-1566385101042-1a0aa0c12e8c?auto=format&fit=crop&q=80&w=400' },
    { id: 3, name: 'Sut mahsulotlari', price: 12500, stock: 45, image: 'https://images.unsplash.com/photo-1550583724-125581fe2f8a?auto=format&fit=crop&q=80&w=400' },
  ]);

  // Xaridorlar state
  const [customers, setCustomers] = useState([
    { id: 1, name: 'Ali Valiyev', phone: '+998 90 123 45 67' },
    { id: 2, name: 'Guli Anvarova', phone: '+998 93 456 78 90' },
  ]);

  const [cartItems, setCartItems] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCustomer, setSelectedCustomer] = useState(null);
  const [isCustomerDropdownOpen, setIsCustomerDropdownOpen] = useState(false);
  const [customerSearch, setCustomerSearch] = useState('');
  const [showAddCustomer, setShowAddCustomer] = useState(false);
  const [newCustomer, setNewCustomer] = useState({ name: '', phone: '' });
  const [toast, setToast] = useState({ show: false, message: '', type: '' });

  // Toast xabarini avtomatik yopish
  useEffect(() => {
    if (toast.show) {
      const timer = setTimeout(() => setToast({ ...toast, show: false }), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const showToast = (message, type = 'error') => {
    setToast({ show: true, message, type });
  };

  // Mahsulotlar qidiruvi
  const filteredProducts = useMemo(() => {
    if (!searchTerm.trim()) return [];
    return products.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()));
  }, [searchTerm, products]);

  // Xaridorlar qidiruvi
  const filteredCustomers = useMemo(() => {
    return customers.filter(c => 
      c.name.toLowerCase().includes(customerSearch.toLowerCase()) || 
      c.phone.includes(customerSearch)
    );
  }, [customerSearch, customers]);

  // Savat amallari
  const addToCart = (product) => {
    setCartItems(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setSearchTerm('');
  };

  const updateQuantity = (id, delta) => {
    setCartItems(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const removeFromCart = (id) => setCartItems(prev => prev.filter(item => item.id !== id));

  const totalAmount = cartItems.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cartItems.reduce((sum, item) => sum + item.quantity, 0);

  // Yangi xaridor qo'shish
  const handleAddCustomer = () => {
    if (!newCustomer.name || !newCustomer.phone) {
      showToast('Ism va telefonni to\'liq kiriting!');
      return;
    }

    const exists = customers.find(c => c.name === newCustomer.name || c.phone === newCustomer.phone);
    if (exists) {
      showToast('Bu xaridor yoki telefon raqami allaqachon mavjud!');
      return;
    }

    const created = { id: Date.now(), ...newCustomer };
    setCustomers([...customers, created]);
    setSelectedCustomer(created);
    setShowAddCustomer(false);
    setNewCustomer({ name: '', phone: '' });
    setIsCustomerDropdownOpen(false);
    showToast('Xaridor muvaffaqiyatli qo\'shildi!', 'success');
  };

  // Savdoni yakunlash
  const handleCompleteSale = () => {
    if (!selectedCustomer) {
      showToast('Xaridor nomini kiriting yoki tanlang!');
      return;
    }
    if (cartItems.length === 0) {
      showToast('Savatda mahsulot yo\'q!');
      return;
    }

    // Tarixga qo'shish simulatsiyasi
    const saleData = {
      customer: selectedCustomer,
      items: cartItems,
      total: totalAmount,
      date: new Date().toISOString()
    };
    console.log('Savdo yakunlandi:', saleData);

    showToast('Savdo muvaffaqiyatli yakunlandi!', 'success');
    setCartItems([]);
    setSelectedCustomer(null);
    setCustomerSearch('');
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-gray-900">
      {/* Toast Notification */}
      {toast.show && (
        <div className={`fixed top-24 right-6 z-[100] flex items-center gap-3 px-6 py-4 rounded-2xl shadow-2xl animate-in slide-in-from-right duration-300 ${
          toast.type === 'success' ? 'bg-green-600 text-white' : 'bg-red-600 text-white'
        }`}>
          {toast.type === 'success' ? <CheckCircle className="w-6 h-6" /> : <AlertCircle className="w-6 h-6" />}
          <span className="font-bold">{toast.message}</span>
        </div>
      )}

      <nav className="fixed w-full top-0 z-50 bg-white border-b border-gray-100 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-8 h-full">
            <NavLink to="/products"><Package className="w-5 h-5" /><span>Mahsulotlar</span></NavLink>
            <NavLink to="/sales" active><BarChart2 className="w-5 h-5" /><span>Savdo</span></NavLink>
            <NavLink to="/history"><History className="w-5 h-5" /><span>Tarix</span></NavLink>
          </div>
          <button onClick={() => navigate('/login')} className="text-gray-500 hover:text-red-600 font-semibold"><LogOut className="w-5 h-5 inline mr-2" /> Chiqish</button>
        </div>
      </nav>

      <main className="pt-32 pb-20 px-6 max-w-7xl mx-auto">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

          {/* Chap ustun: Qidiruv va Savat */}
          <div className="lg:col-span-2 space-y-6">
            <div className="relative">
              <Search className="absolute left-5 top-1/2 -translate-y-1/2 w-6 h-6 text-gray-400" />
              <input 
                type="text" 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder="Mahsulotlarni qidirish..."
                className="w-full pl-14 pr-6 py-5 rounded-[2rem] border-none shadow-md outline-none text-lg focus:ring-2 focus:ring-purple-200 transition-all"
              />
              {filteredProducts.length > 0 && (
                <div className="absolute top-full left-0 right-0 mt-3 bg-white rounded-[2rem] shadow-xl z-40 border border-gray-100 overflow-hidden">
                  {filteredProducts.map(p => (
                    <button key={p.id} onClick={() => addToCart(p)} className="w-full flex items-center justify-between p-4 hover:bg-purple-50 transition-colors">
                      <div className="flex items-center gap-4">
                        <img src={p.image} alt={p.name} className="w-12 h-12 rounded-xl object-cover" />
                        <span className="font-bold">{p.name}</span>
                      </div>
                      <span className="font-black text-purple-700">{p.price.toLocaleString()} UZS</span>
                    </button>
                  ))}
                </div>
              )}
            </div>

            <div className="bg-white rounded-[2.5rem] shadow-md border border-gray-50 flex flex-col min-h-[500px]">
              <div className="p-8 border-b border-gray-50 flex justify-between items-center">
                <h2 className="text-2xl font-black flex items-center gap-3">
                  <ShoppingCart className="w-7 h-7 text-purple-700" /> Savat
                </h2>
                {cartItems.length > 0 && (
                  <button onClick={() => setCartItems([])} className="text-red-500 font-bold hover:text-red-700 flex items-center gap-2">
                    <Trash2 className="w-5 h-5" /> Tozalash
                  </button>
                )}
              </div>
              <div className="flex-1 overflow-y-auto max-h-[450px] p-8">
                {cartItems.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-60">
                    <ShoppingCart className="w-16 h-16 mb-4" />
                    <p className="text-xl font-bold">Savat bo'sh</p>
                  </div>
                ) : (
                  <div className="space-y-4">
                    {cartItems.map((item) => (
                      <div key={item.id} className="flex items-center gap-4 p-4 bg-slate-50 rounded-3xl border border-transparent hover:border-purple-100 transition-all">
                        <img src={item.image} alt={item.name} className="w-20 h-20 rounded-2xl object-cover" />
                        <div className="flex-1">
                          <h4 className="font-bold text-gray-900">{item.name}</h4>
                          <p className="text-purple-700 font-black">{item.price.toLocaleString()} UZS</p>
                        </div>
                        <div className="flex items-center gap-3 bg-white rounded-2xl p-1.5 shadow-sm border border-gray-100">
                          <button onClick={() => updateQuantity(item.id, -1)} className="p-2 hover:bg-slate-50 rounded-lg"><Minus className="w-4 h-4" /></button>
                          <span className="font-black w-8 text-center">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.id, 1)} className="p-2 hover:bg-slate-50 rounded-lg"><Plus className="w-4 h-4" /></button>
                        </div>
                        <button onClick={() => removeFromCart(item.id)} className="text-gray-300 hover:text-red-500 p-2"><Trash2 className="w-6 h-6" /></button>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* O'ng ustun: Xaridor va Hisob-kitob */}
          <div className="space-y-6">
            <div className="bg-white rounded-[2.5rem] p-8 shadow-md border border-gray-50">
              <h3 className="text-xl font-black mb-6 flex items-center gap-3 text-gray-900">
                <User className="w-6 h-6 text-purple-700" /> Xaridor ma'lumotlari
              </h3>

              <div className="relative mb-4">
                <div 
                  onClick={() => setIsCustomerDropdownOpen(!isCustomerDropdownOpen)}
                  className="w-full bg-slate-50 border border-gray-100 rounded-2xl px-5 py-4 font-bold text-gray-700 cursor-pointer flex justify-between items-center"
                >
                  <span className={selectedCustomer ? 'text-gray-900' : 'text-gray-400'}>
                    {selectedCustomer ? selectedCustomer.name : 'Xaridorni tanlang...'}
                  </span>
                  <ChevronDown className={`w-5 h-5 transition-transform ${isCustomerDropdownOpen ? 'rotate-180' : ''}`} />
                </div>

                {isCustomerDropdownOpen && (
                  <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-2xl shadow-2xl border border-gray-100 z-50 overflow-hidden animate-in fade-in zoom-in duration-200">
                    <div className="p-3 border-b border-gray-50">
                      <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                        <input 
                          type="text"
                          autoFocus
                          value={customerSearch}
                          onChange={(e) => setCustomerSearch(e.target.value)}
                          placeholder="Qidirish..."
                          className="w-full pl-10 pr-4 py-2 bg-slate-50 rounded-xl outline-none text-sm font-bold"
                        />
                      </div>
                    </div>
                    <div className="max-h-[200px] overflow-y-auto">
                      {filteredCustomers.map(c => (
                        <button 
                          key={c.id}
                          onClick={() => {
                            setSelectedCustomer(c);
                            setIsCustomerDropdownOpen(false);
                            setCustomerSearch('');
                          }}
                          className="w-full text-left px-5 py-3 hover:bg-purple-50 transition-colors border-b border-gray-50 last:border-0"
                        >
                          <p className="font-bold text-gray-900">{c.name}</p>
                          <p className="text-xs text-gray-500">{c.phone}</p>
                        </button>
                      ))}
                    </div>
                    <button 
                      onClick={() => {
                        setShowAddCustomer(true);
                        setIsCustomerDropdownOpen(false);
                      }}
                      className="w-full p-4 text-purple-700 font-black hover:bg-purple-50 transition-colors flex items-center justify-center gap-2 border-t border-gray-100"
                    >
                      <UserPlus className="w-5 h-5" /> Yangi xaridor qo'shish
                    </button>
                  </div>
                )}
              </div>

              {selectedCustomer && !showAddCustomer && (
                <div className="bg-purple-50 p-5 rounded-2xl border border-purple-100 animate-in zoom-in duration-300">
                  <div className="flex items-center gap-3 mb-2">
                    <UserCheck className="w-5 h-5 text-purple-700" />
                    <span className="font-black text-purple-900">{selectedCustomer.name}</span>
                  </div>
                  <div className="flex items-center gap-2 text-purple-600 font-bold text-sm">
                    <Phone className="w-4 h-4" /> {selectedCustomer.phone}
                  </div>
                </div>
              )}

              {showAddCustomer && (
                <div className="space-y-4 bg-slate-50 p-5 rounded-2xl border border-gray-100 animate-in slide-in-from-top duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <h4 className="font-black text-gray-900">Yangi xaridor</h4>
                    <button onClick={() => setShowAddCustomer(false)}><X className="w-5 h-5 text-gray-400" /></button>
                  </div>
                  <input 
                    type="text" 
                    placeholder="Ismi"
                    value={newCustomer.name}
                    onChange={(e) => setNewCustomer({...newCustomer, name: e.target.value})}
                    className="w-full px-4 py-3 rounded-xl border border-gray-200 outline-none focus:ring-2 focus:ring-purple-200 font-bold"
                  />
                  <input 
                    type="tel" 
                    placeholder="Telefon"
                    value={newCustomer.phone}
                    onChange={(e) => setNewCustomer({...newCustomer, phone: e.target.value})}
                    className="w-full px-4 py-3 rounded-xl border border-gray-200 outline-none focus:ring-2 focus:ring-purple-200 font-bold"
                  />
                  <button 
                    onClick={handleAddCustomer}
                    className="w-full bg-purple-700 text-white py-3 rounded-xl font-black hover:bg-purple-800 transition-all shadow-md active:scale-95"
                  >
                    Qo'shish va tanlash
                  </button>
                </div>
              )}
            </div>

            <div className="bg-white rounded-[2.5rem] p-8 shadow-md border border-gray-50">
              <div className="space-y-4 mb-8">
                <div className="flex justify-between items-center text-gray-500 font-bold">
                  <span>Mahsulotlar soni</span>
                  <span className="text-gray-900 bg-slate-100 px-3 py-1 rounded-full text-sm">{totalItems} ta</span>
                </div>
                <hr className="border-gray-50" />
                <div className="flex justify-between items-end">
                  <div>
                    <p className="text-gray-400 font-black uppercase tracking-widest text-xs mb-1">Jami summa</p>
                    <p className="text-3xl font-black text-purple-700">{totalAmount.toLocaleString()} <span className="text-sm">UZS</span></p>
                  </div>
                </div>
              </div>

              <button 
                onClick={handleCompleteSale}
                className="w-full py-5 rounded-2xl font-black text-xl bg-purple-700 text-white hover:bg-purple-800 transition-all shadow-xl shadow-purple-200 active:scale-[0.98]"
              >
                Savdoni yakunlash
              </button>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

const NavLink = ({ to, children, active = false }) => (
  <Link 
    to={to} 
    className={`flex items-center gap-2 px-1 h-full font-bold transition-all relative group ${
      active ? 'text-purple-700' : 'text-gray-500 hover:text-purple-600'
    }`}
  >
    {children}
    {active && (
      <div className="absolute bottom-0 left-0 right-0 h-1 bg-purple-700 rounded-t-full"></div>
    )}
  </Link>
);

export default Sales;
